function isPrime(n) {
  if (n < 2) return false;
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) return false;
  }
  return true;
}

tests:
if (isPrime(2) !== true) throw new Error('2');
if (isPrime(1) !== false) throw new Error('1');
if (isPrime(97) !== true) throw new Error('97');
if (isPrime(100) !== false) throw new Error('100');
if (isPrime(0) !== false) throw new Error('0');

