solution:
function fastPow(base, exp) {
  let result = 1;
  while (exp > 0) {
    if (exp & 1) result *= base;
    base *= base;
    exp = Math.trunc(exp / 2);
  }
  return result;
}

tests:
if (fastPow(2, 10) !== 1024) throw new Error('2^10');
if (fastPow(3, 0) !== 1) throw new Error('3^0');
if (fastPow(5, 3) !== 125) throw new Error('5^3');
if (fastPow(7, 1) !== 7) throw new Error('7^1');
if (fastPow(2, 0) !== 1) throw new Error('2^0');
if (fastPow(2, 16) !== 65536) throw new Error('2^16');

