solution:
function binarySearch(xs, target) {
  let lo = 0, hi = xs.length - 1;
  while (lo <= hi) {
    const mid = lo + Math.trunc((hi - lo) / 2);
    if (xs[mid] === target) return mid;
    if (xs[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

tests:
if (binarySearch([1, 3, 5, 7, 9], 7) !== 3) throw new Error('a');
if (binarySearch([1, 3, 5, 7, 9], 1) !== 0) throw new Error('b');
if (binarySearch([1, 3, 5, 7, 9], 9) !== 4) throw new Error('c');
if (binarySearch([1, 3, 5, 7, 9], 4) !== -1) throw new Error('d');
if (binarySearch([], 5) !== -1) throw new Error('e');
if (binarySearch([2], 2) !== 0) throw new Error('f');
